import chromadb
from chromadb.utils import embedding_functions
import json

openai_ef = embedding_functions.OpenAIEmbeddingFunction(
    api_key="...",
    model_name="text-embedding-3-small",
)

class SkillLibrary:
    def __init__(self, path: str = "./skill_db"):
        self.client = chromadb.PersistentClient(path=path)
        self.col = self.client.get_or_create_collection(
            name="skills",
            embedding_function=openai_ef,
        )
        # In-memory map for fast code retrieval
        self._skills: dict[str, Skill] = {}

    def add(self, skill: Skill) -> None:
        """Add a new skill to the library."""
        self.col.add(
            ids=[skill.id],
            documents=[skill.to_index_text()],
            metadatas=[{
                "name": skill.name,
                "signature": skill.signature,
                "code": skill.code,
                "tags": ",".join(skill.tags),
                "version": skill.version,
            }],
        )
        self._skills[skill.id] = skill

    def search(self, query: str, k: int = 3, min_similarity: float = 0.5) -> list[Skill]:
        """Retrieve top-k skills matching the query."""
        if self.col.count() == 0:
            return []
        results = self.col.query(
            query_texts=[query],
            n_results=min(k, self.col.count()),
            include=["distances", "metadatas", "ids"],
        )
        found = []
        for dist, meta, sid in zip(
            results["distances"][0],
            results["metadatas"][0],
            results["ids"][0],
        ):
            similarity = 1 - dist
            if similarity >= min_similarity:
                skill = self._skills.get(sid) or Skill(
                    id=sid,
                    name=meta["name"],
                    description="",
                    signature=meta["signature"],
                    code=meta["code"],
                )
                found.append(skill)
        return found

    def execute(self, skill: Skill, **kwargs) -> Any:
        """Run a skill's code in a local namespace and capture its result."""
        namespace: dict = {}
        exec(skill.code, namespace)  # load skill function into namespace
        fn = namespace.get(skill.name)
        if fn is None:
            raise ValueError(f"Skill function '{skill.name}' not found in code.")
        try:
            result = fn(**kwargs)
            skill.success_count += 1
            return result
        except Exception as e:
            skill.failure_count += 1
            raise
